  PRIMARY KEY (`ai_review_id`),
  KEY `idx_ar_status` (`ar_status_id`),
  KEY `idx_pr_repo` (`pr_id`,`repo_id`),
  CONSTRAINT `fk_ar_pr` FOREIGN KEY (`pr_id`, `repo_id`) REFERENCES `pr` (`pr_id`, `repo_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_ar_status` FOREIGN KEY (`ar_status_id`) REFERENCES `ai_review_status` (`ar_status_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='AI 리뷰 정보';
