  `repo_id` int NOT NULL COMMENT 'repo_id',
  `pr_id` int NOT NULL COMMENT 'pr_id',
  `status` int DEFAULT '0' COMMENT '리뷰 생성 상태 (0:대기중, 1:생성완료)',
  `send_at` datetime DEFAULT NULL COMMENT 'status 전송 시간',
  PRIMARY KEY (`ar_status_id`),
  KEY `ai_review_queue_ibfk_1` (`repo_id`),
  KEY `ai_review_queue_ibfk_2` (`pr_id`,`repo_id`),
  CONSTRAINT `ai_review_queue_ibfk_1` FOREIGN KEY (`repo_id`) REFERENCES `repository` (`repo_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `ai_review_queue_ibfk_2` FOREIGN KEY (`pr_id`, `repo_id`) REFERENCES `pr` (`pr_id`, `repo_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=227 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
