DROP TABLE IF EXISTS `change_file`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `change_file` (
  `file_id` varchar(255) NOT NULL COMMENT '파일변경 id',
  `repo_id` int NOT NULL COMMENT 'repo_id',
  `pr_id` int NOT NULL COMMENT 'pr_id',
  `file_name` varchar(255) DEFAULT NULL COMMENT '파일명',
  `old_path` varchar(255) DEFAULT NULL COMMENT '변경 전 경로',
  `new_path` varchar(255) DEFAULT NULL COMMENT '변경 후 경로',
  `file_status` int DEFAULT NULL COMMENT '1. add , 2. update, 3. delete',
  `commit_id` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`file_id`,`repo_id`,`pr_id`),
  KEY `change_file_ibfk_1` (`repo_id`),
  KEY `change_file_ibfk_2` (`pr_id`,`repo_id`),
  CONSTRAINT `change_file_ibfk_1` FOREIGN KEY (`repo_id`) REFERENCES `repository` (`repo_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `change_file_ibfk_2` FOREIGN KEY (`pr_id`, `repo_id`) REFERENCES `pr` (`pr_id`, `repo_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

