--
-- Table structure for table `comment`
--

DROP TABLE IF EXISTS `comment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `comment` (
  `comment_id` int NOT NULL COMMENT 'comment_id',
  `pr_id` int NOT NULL COMMENT 'pr_id',
  `repo_id` int NOT NULL COMMENT 'repo_id',
  `file_id` varchar(255) DEFAULT NULL,
  `content` text,
  `comment_type` int DEFAULT NULL COMMENT '댓글 유형(댓글, 질문 등)',
  `user_id` int DEFAULT NULL COMMENT 'user_id',
  `dis_id` varchar(255) DEFAULT NULL COMMENT '디스커션 id',
  `create_at` varchar(255) NOT NULL COMMENT '댓글 생성날짜',
  `new_line` int DEFAULT NULL COMMENT '새로운 코드 줄 번호',
  `old_line` int DEFAULT NULL COMMENT '이전 코드 줄 번호',
  `new_start_line` int DEFAULT NULL COMMENT '변경 후 코드의 시작 줄',
  `new_end_line` int DEFAULT NULL COMMENT '변경 후 코드의 마지막 줄',
  `old_start_line` int DEFAULT NULL COMMENT '변경 전 코드의 시작 줄',
  `old_end_line` int DEFAULT NULL COMMENT '변경 후 코드의 마지막줄',
  `image_name` varchar(255) DEFAULT NULL,
  `comment_value` int DEFAULT '0' COMMENT '0:미전송 1:전송',
  PRIMARY KEY (`comment_id`,`pr_id`,`repo_id`),
  UNIQUE KEY `comment_id` (`comment_id`),
  KEY `comment_ibfk_1` (`repo_id`),
  KEY `comment_ibfk_2` (`pr_id`,`repo_id`),
  KEY `comment_ibfk_3` (`user_id`),
  CONSTRAINT `comment_ibfk_1` FOREIGN KEY (`repo_id`) REFERENCES `repository` (`repo_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `comment_ibfk_2` FOREIGN KEY (`pr_id`, `repo_id`) REFERENCES `pr` (`pr_id`, `repo_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `comment_ibfk_3` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `comment`
--

