6f69577/LOGO.png)',0,22147,'369a352c2e7e54af0e96a44a3a6d1149767551e9','2025-01-30T21:37:53.894+09:00',0,0,0,0,0,0,NULL,0),(1874127,15,888788,NULL,'이것은 수정한 댓글입니다.',0,22147,'043d5512e74491e96c16387a2d820a7cbd682018','2025-01-30T20:45:54.002+09:00',0,0,0,0,0,0,NULL,0),(1874761,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','사용하지 않는 코드라면 지워도 될 것 같습니다. 수정하지마. 아니수정해',0,22219,'a0124e9547dcd285a942adf3a8986d1006e6279a','2025-02-12T11:16:56.255+09:00',39,0,39,39,0,0,NULL,1),(1874763,17,888788,NULL,'수고하셨습니다. 문득 든 생각인데 pr이라는 명칭에 대해서는 어떻게 생각하시나요? 그렇게 명시적인 이름은 아닌거 같아서 이후 여유가 된다면 pullrequest로 수정하는 것도 나쁘지 않겠다는 생각입니다. 코멘트 남긴 부분만 조금 수정하시면 좋을 것 같습니다!',0,22219,'6b9fcf9fcfaf00d67cb10020dbd1dbe4ddea4330','2025-01-31T09:50:55.882+09:00',0,0,0,0,0,0,NULL,1),(1876410,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22147,'44a45d838367eac925968f85a6fcf859b9ffaf03','2025-01-31T15:23:12.163+09:00',155,126,0,0,0,0,NULL,1),(1876413,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22147,'76b258967469d53d3607f62ebff7f838020a2c04','2025-01-31T15:23:56.862+09:00',155,126,0,0,0,0,NULL,1),(1876682,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22219,'e5ddb4437ef8c60924ed4b0e6ccaf5154196582f','2025-01-31T15:47:03.164+09:00',168,139,0,0,0,0,NULL,1),(1876683,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22219,'b0d6b41d9d0c895f5d7b763ac178d1bd32bfe49b','2025-01-31T15:47:13.252+09:00',168,139,0,0,0,0,NULL,1),(1876684,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22219,'0f230e20ecaeeeb604c55314574fd944c381c17a','2025-01-31T15:47:16.350+09:00',168,139,0,0,0,0,NULL,1),(1876691,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22219,'723e28586d8e6b5d323be1417acb790288a21fce','2025-01-31T15:48:01.746+09:00',168,139,0,0,0,0,NULL,1),(1876695,17,888788,'524cec10819d109f27582f3dd600dc7a0ef4d500','라인별로 댓글 달기 테스트',0,22219,'e9214dfa2a03f930e63cc14723b56e99bf0cae8c','20