/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`%`*/ /*!50003 TRIGGER `noti_trg_after_insert_comment_temp` AFTER INSERT ON `comment_temp` FOR EACH ROW BEGIN
    DECLARE pr_title VARCHAR(255) DEFAULT 'No Title';  -- 기본값 설정

    -- PR ID를 기반으로 title 조회
    SELECT title INTO pr_title
    FROM pr
    WHERE pr_id = NEW.pr_id
    AND repo_id = NEW.repo_id
    LIMIT 1;

    -- notification 테이블에 데이터 삽입
    INSERT INTO notification (
        user_id,
        repo_id,
        noti_message,
        send_type,
        noti_type,
        send_time,
        msg_status
    ) VALUES (
        NEW.user_id,
        NEW.repo_id,
        pr_title,
        1,  -- 기본값: mm
        3,  -- comment
        NULL,  -- 전송 시간 (NULL 가능하면 그대로 사용)
        0   -- 미전송 상태
    );
END */;;
