DROP TABLE IF EXISTS `pr`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `pr` (
  `pr_id` int NOT NULL COMMENT 'pr_id',
  `repo_id` int NOT NULL COMMENT 'repo_id',
  `title` varchar(255) DEFAULT NULL COMMENT 'PR 제목',
  `description` longtext COMMENT 'PR 설명',
  `user_id` int NOT NULL COMMENT 'PR 생성자 아이디',
  `create_at` varchar(255) NOT NULL COMMENT 'MR 생성날짜',
  `is_opened` int NOT NULL DEFAULT '1' COMMENT 'PR 상태 1:merged, 2:opened, 3:closed',
  `source_branch` varchar(255) DEFAULT NULL COMMENT '소스 브랜치',
  `target_branch` varchar(255) DEFAULT NULL COMMENT '대상 브랜치',
  `base_sha` varchar(255) DEFAULT NULL,
  `head_sha` varchar(255) DEFAULT NULL,
  `start_sha` varchar(255) DEFAULT NULL,
  `user_name` varchar(255) NOT NULL COMMENT 'MR 생성자 이름',
  `user_profile` varchar(255) DEFAULT NULL COMMENT 'MR 생성자 프로필 이미지',
  `pr_type` int NOT NULL DEFAULT '0' COMMENT '0.알람X / 1.알람 적용',
  PRIMARY KEY (`pr_id`,`repo_id`),
  KEY `pr_ibfk_1` (`user_id`),
  KEY `pr_ibfk_2` (`repo_id`),
  CONSTRAINT `pr_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON UPDATE CASCADE,
  CONSTRAINT `pr_ibfk_2` FOREIGN KEY (`repo_id`) REFERENCES `repository` (`repo_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
