94fb3c319344be2bc2c0533','5b7a6146752b83f400e07854dfe27bf7000cf058','이해루','https://secure.gravatar.com/avatar/64d76aebe92226f9ea325dc5d35a44327d62594998d76d6905a47b6a0f61ae92?s=80&d=identicon',0),(33,888788,'테스트용 MR','',22219,'2025-02-03T17:05:53.553+09:00',3,'FE/feature/MarkDownEditor','develop',NULL,NULL,NULL,'이해루','https://secure.gravatar.com/avatar/64d76aebe92226f9ea325dc5d35a44327d62594998d76d6905a47b6a0f61ae92?s=80&d=identicon',0),(34,888788,'#S12P11B108-51 [BE] 파일 변경사항 구현','\n## 📌 Related Issue\n\n<!-- 관련된 이슈 번호를 #과 함께 작성해주세요 -->\n\n- Closes #S12P11B108-32\n- Closes #S12P11B108-46\n- Closes #S12P11B108-47\n- Closes #S12P11B108-48\n- Closes #S12P11B108-49\n- Closes #S12P11B108-51\n- Closes #S12P11B108-53\n\n\n<br/>\n\n## ✏ Content\n\n<!-- 작업한 내용을 간단히 설명해주세요 -->\nGitLab 기반 PR 기능 구현\n- PR, Commit, File, Comment 관련 로직 구현\n\n<br/>\n\n## 📑 참고 사항\n\n<!-- PR 승인 전 확인해야 할 사항들을 설명해주세요 (ex. 스크린샷, 코드) -->\n**TODO**\n- 댓글 및 대댓글 구현 로직에서 코드별 댓글도 같이 조회하는 로직으로 수정이 필요합니다.\n- 댓글 이미지 업로드 구현이 필요합니다.',22147,'2025-02-03T17:48:51.266+09:00',1,'BE/feature/pr','develop','4247c0fe5238c2b666ecf9c61ef7a0deed2911f9','f452abe8280ca8a6277909592cf7c56aae5e952e','4247c0fe5238c2b666ecf9c61ef7a0deed2911f9','신지혜','https://secure.gravatar.com/avatar/5a7047c33f01f87edfef9789e87cc5e3604ac367b6589f9e8a43bf7465ab8e24?s=80&d=identicon',0),(35,888788,'swagger 추가 및 pr 관련 뒷단 rest 호출 구현 MR',NULL,22204,'2025-02-04T13:24:14.958+09:00',1,'BE/feature/endpiont','develop',NULL,NULL,NULL,'조창훈','https://secure.gravatar.com/avatar/1ee5b9b1573716725c6e5a318973071ee8ca657c2892e497949f9de53f947f0b?s=80&d=identicon',0),(36,888788,'fix: swagger 화면 안나오는 문제 경로 수정하여 처리',NULL,22204,'2025-02-04T13:37:00.007+09:00',1,'BE/hotfix/swagger','develop','16d9d8f843c66ae23400097e5915712df9d4bf39','3f84c87e27a5b84857d11cc4d7097e15b4e45ec9','16d9d8f843c66ae23400097e5915712df9d4bf39','조창훈','https://secure.gravatar.com/avatar/1ee5b9b1573716725c6e5a318973071ee8ca657c2892e497949f9de53f947f0b?s=80&d=identicon',0),(37,888788,'발생한 CORS 관련 Con