/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`%`*/ /*!50003 TRIGGER `noti_trg_after_insert_pr` AFTER INSERT ON `pr` FOR EACH ROW BEGIN
    IF NEW.pr_type = 1 THEN
        INSERT INTO notification (
            user_id,
            repo_id,
            noti_message,
            send_type,
            noti_type,
            send_time,
            msg_status
        ) VALUES (
            NEW.user_id,
            NEW.repo_id,
            NEW.title,
            1,  -- 기본값: mm
            1,  -- PR 알림
            NULL,  -- 전송 시간 (NULL 가능하면 그대로 사용)
            0   -- 미전송 상태
        );
    END IF;
END */;;
