/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`%`*/ /*!50003 TRIGGER `trg_pr_ai_review_update` AFTER UPDATE ON `pr` FOR EACH ROW BEGIN
    IF NEW.pr_type = 1 THEN
        -- `ai_review_status`에 같은 `repo_id`, `pr_id` 값이 있는지 확인
        IF (SELECT COUNT(*) FROM ai_review_status 
            WHERE repo_id = NEW.repo_id 
            AND pr_id = NEW.pr_id) = 0 THEN
            
            -- 값이 없으면 INSERT 실행
            INSERT INTO ai_review_status (repo_id, pr_id, status)
            VALUES (NEW.repo_id, NEW.pr_id, 0);
        END IF;
    END IF;
END */;;
DELIMITER ;
