CREATE TABLE `reply` (
  `re_comment_id` int NOT NULL COMMENT '대댓글_id',
  `repo_id` int NOT NULL COMMENT 'repo_id',
  `pr_id` int NOT NULL COMMENT 'pr_id',
  `comment_id` int NOT NULL COMMENT '댓글_id',
  `dis_id` varchar(255) DEFAULT NULL COMMENT '디스커션 id',
  `user_id` int NOT NULL COMMENT '유저_id',
  `content` varchar(255) DEFAULT NULL COMMENT '대댓글 내용',
  `recomment_type` int DEFAULT NULL COMMENT '답글 유형(댓글, 질문 등)',
  `create_at` varchar(255) DEFAULT NULL,
  `reply_type` int DEFAULT NULL,
  `reply_value` int DEFAULT '0' COMMENT '0:미전송 1:전송',
  PRIMARY KEY (`re_comment_id`,`comment_id`,`pr_id`,`repo_id`),
  UNIQUE KEY `re_comment_id` (`re_comment_id`),
  KEY `reply_ibfk_1` (`comment_id`,`pr_id`,`repo_id`),
  KEY `reply_ibfk_2` (`user_id`),
  CONSTRAINT `reply_ibfk_1` FOREIGN KEY (`comment_id`, `pr_id`, `repo_id`) REFERENCES `comment` (`comment_id`, `pr_id`, `repo_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `reply_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
